# Phase 1: exploration (one-time, or per UI change)
function explore(app):
    docs = []
    for screen in walk(app):
        for element in screen.elements:
            interact_and_observe(element)            # click/hover/scroll
            doc = llm.describe(
                element=element,
                before=screen.before,
                after=screen.after,
            )                                        # what / does / when-to-use
            docs.append({"id": element.id, "doc": doc, "path": element.path})
    index = vector_index(docs)
    save(index, "element_docs.idx")
    return index

# Phase 2: deployment (per task)
function act(task, index):
    plan = llm.plan(task)
    for step in plan:
        candidates = index.search(step.description, k=5)   # retrieve docs
        chosen = llm.pick_element(step, candidates)
        controller.execute(chosen.id, step.args)

    return done()

function augmented_llm(user_message):
    # all three augmentations are model-driven, not orchestrator-driven
    tools = [
        retrieve(query),         # corpus-side knowledge
        call_tool(name, args),   # side-effecting actions
        memory_read(key),        # cross-turn state
        memory_write(key, value),
    ]

    messages = [
        system_prompt,
        memory.summary(),        # prior session state surfaced as context
        user(user_message),
    ]

    for step in 1..MAX_STEPS:
        reply = llm.generate(messages=messages, tools=tools)
        messages.append(reply)

        if not reply.tool_calls:
            memory.commit(messages)        # persist what mattered
            return reply.content

        for call in reply.tool_calls:
            result = dispatch(call)         # retrieve | tool | memory
            messages.append(tool_result(call.id, result))

    return abort("step budget exhausted")

