function answer(question):
    messages = [system_prompt, user(question)]
    for step in 1..MAX_STEPS:
        reply = llm.generate(messages=messages, tools=[run_code])
        messages.append(reply)

        if not reply.tool_calls:
            return reply.content         # final answer

        for call in reply.tool_calls:
            if call.name != "run_code":
                continue
            stdout, stderr, value = sandbox.execute(call.args.code)
            messages.append(tool_result(call.id, {
                "stdout": stdout, "stderr": stderr, "value": value
            }))
        # next iteration: model sees the run output and continues

    return abort("step budget exhausted")

