#   list("/slack/eng/")
#   find("/notion", "*onboarding*")
#   search("incident 2026-05", "/slack/eng")

registry = {}      # keyed by entry id

function register(kind, entry):
    assert kind in {"tool", "agent"}
    registry[entry.id] = {
        "kind": kind,
        "description": entry.description,
        "capabilities": entry.capabilities,
        "cost_per_call": entry.cost,
        "p50_latency_ms": entry.latency,
        "quality_score": entry.quality,
        "handle": entry.handle,        # callable or A2A endpoint
    }

function query(task):
    candidates = [
        e for e in registry.values()
        if matches(e["description"], task) or matches(e["capabilities"], task)
    ]
    return rank(candidates, by=["quality_score", "-cost_per_call", "-p50_latency_ms"])

function dispatch(task):
    ranked = query(task)
    if not ranked: return abort("no capable tool or agent found")
    chosen = ranked[0]
    return chosen["handle"](task)      # call tool or invoke agent uniformly

PALETTE = {}
LAST_REFRESH = 0

function discover(registry, ttl_seconds=300):
    global LAST_REFRESH
    if now() - LAST_REFRESH < ttl_seconds and PALETTE:
        return PALETTE                            # cache hit

    advertised = registry.list_tools()            # MCP, internal dir, etc.
    PALETTE = {}
    for t in advertised:
        if not schema_valid(t.input_schema):
            log_warn("skipping malformed tool", t.name)
            continue
        PALETTE[t.name] = {
            "description": t.description,
            "input_schema": t.input_schema,
            "invoke": t.invoke,
        }
    LAST_REFRESH = now()
    return PALETTE

function run(user_message, registry):
    tools = discover(registry)
    return agent_loop(user_message, tools=tools)  # palette is dynamic per call

function run(user_message):
    messages = [system_prompt, user(user_message)]
    tools = registry.list()              # typed JSON-Schema palette

    for step in 1..MAX_STEPS:
        reply = llm.generate(messages=messages, tools=tools)
        messages.append(reply)

        if not reply.tool_calls:
            return reply.content         # model answered

        for call in reply.tool_calls:
            if not registry.validate(call.name, call.args):
                messages.append(tool_error(call.id, "schema invalid"))
                continue
            result = registry.execute(call.name, call.args)
            messages.append(tool_result(call.id, result))
        # next iteration: model sees results and decides next move

    return abort("step budget exhausted")

# CORPUS = unlabelled text. TOOLS = e.g. calculator, search, qa, translate.

function sample_candidates(passage):
    # ask the base model to propose tool calls at plausible positions
    return base_llm.propose_calls(passage, tools=TOOLS, k=K)

function execute_and_splice(passage, call):
    answer = TOOLS[call.name].invoke(call.args)
    # splice "[<name>(args) → answer]" into the passage at the proposed position
    return splice(passage, call.pos, render_call(call, answer))

function usefulness(passage, augmented, target_continuation):
    base = nll(base_llm, passage,    target_continuation)
    aug  = nll(base_llm, augmented, target_continuation)
    return base - aug                  # positive = perplexity drop

training_data = []
for passage in CORPUS:
    for call in sample_candidates(passage):
        aug = execute_and_splice(passage, call)
        if usefulness(passage, aug, gold_continuation_after(passage, call.pos)) > THRESHOLD:
            training_data.append(aug)  # keep helpful insertions only

fine_tune(base_llm, on=training_data)  # model now emits tool calls in-line
